// Client Component
'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';

export default function LoginPage() {
  const router = useRouter();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [remember, setRemember] = useState(false);

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!email.trim()) newErrors.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(email)) newErrors.email = 'Email is invalid';
    if (!password.trim()) newErrors.password = 'Password is required';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);
    setErrors({});

    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();

      if (!res.ok) {
        setErrors({ email: data.error || 'Login failed. Please check your credentials.' });
      } else {
        router.push('/');
        router.refresh(); // so layout uses correct state
      }
    } catch (err: any) {
      setErrors({ email: 'An error occurred during login.' });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full bg-white dark:bg-[#0a0a0a] min-h-[calc(100vh-85px)]">
      <div className="flex flex-col lg:flex-row min-h-[calc(100vh-85px)]">
        {/* Left Side: Illustration */}
        <div className="hidden lg:flex flex-col items-center justify-center relative overflow-hidden lg:w-[40%] xl:w-[45%] bg-[#F0FBF9] dark:bg-[#112220]">
          <div className="w-3/4 max-w-[500px]">
            <Image
              src="/assets/algo_group_109.svg"
              alt="Login illustration"
              width={600}
              height={600}
              className="w-full h-auto opacity-90"
              style={{ width: 'auto', height: 'auto' }}
            />
          </div>
          {/* Decorative circles */}
          <div
            className="absolute rounded-full"
            style={{
              left: '8%',
              top: '12%',
              width: '120px',
              height: '120px',
              backgroundColor: '#36D6BA',
              opacity: 0.15,
            }}
          />
          <div
            className="absolute rounded-full"
            style={{
              right: '5%',
              bottom: '10%',
              width: '180px',
              height: '180px',
              backgroundColor: '#269984',
              opacity: 0.1,
            }}
          />
          <div
            className="absolute rounded-full"
            style={{
              right: '30%',
              top: '5%',
              width: '80px',
              height: '80px',
              backgroundColor: '#36D6BA',
              opacity: 0.2,
            }}
          />
        </div>

        {/* Right Side: Login Form */}
        <div className="flex-1 flex flex-col items-center justify-center px-6 py-12 sm:px-10">
          <div className="w-full max-w-[500px]">
            <h1 className="font-montserrat font-bold text-3xl sm:text-4xl lg:text-5xl text-black dark:text-white mb-3">
              Login
            </h1>
            <p className="font-montserrat text-base sm:text-lg mb-10 text-[#666] dark:text-gray-400">
              Welcome back! Please login to your account.
            </p>

            <form onSubmit={handleSubmit}>
              {/* Email field */}
              <div className="mb-6">
                <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm sm:text-base">
                  Email address
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className={`w-full font-montserrat h-12 sm:h-14 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 sm:px-5 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.email ? 'border-red-500' : ''}`}
                  placeholder="Enter your email"
                />
                {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
              </div>

              {/* Password field */}
              <div className="mb-6">
                <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm sm:text-base">
                  Password
                </label>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={`w-full font-montserrat h-12 sm:h-14 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 sm:px-5 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.password ? 'border-red-500' : ''}`}
                  placeholder="Enter your password"
                />
                {errors.password && <p className="text-red-500 text-xs mt-1">{errors.password}</p>}
              </div>

              {/* Remember me + Forgot password */}
              <div className="flex items-center justify-between mb-10">
                <label className="flex items-center gap-2 cursor-pointer font-montserrat text-sm">
                  <input
                    type="checkbox"
                    checked={remember}
                    onChange={(e) => setRemember(e.target.checked)}
                    className="w-5 h-5 accent-[#36D6BA]"
                  />
                  <span className="text-black dark:text-white">Remember me</span>
                </label>
                <Link
                  href="#"
                  className="font-montserrat font-bold text-sm hover:underline"
                  style={{ color: '#36D6BA' }}
                >
                  Forgot password?
                </Link>
              </div>

              {/* Login button */}
              <button
                className="w-full font-montserrat font-bold text-white h-12 sm:h-14 rounded-lg text-lg sm:text-xl hover:opacity-90 transition-all cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ backgroundColor: '#269984', border: 'none' }}
                disabled={isLoading}
              >
                {isLoading ? 'Logging in...' : 'Login'}
              </button>
            </form>

            {/* Divider */}
            <div className="flex items-center gap-4 my-8">
              <div className="flex-1 h-px bg-[#E0E0E0] dark:bg-neutral-700" />
              <span className="font-montserrat text-sm text-[#999] dark:text-gray-500">or</span>
              <div className="flex-1 h-px bg-[#E0E0E0] dark:bg-neutral-700" />
            </div>

            {/* Social login */}
            <div className="flex gap-4 mb-8">
              <button className="flex-1 flex items-center justify-center gap-3 font-montserrat font-medium h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 rounded-lg text-sm sm:text-base text-[#333] dark:text-white bg-white dark:bg-[#2a2a2a] cursor-pointer hover:bg-gray-50 dark:hover:bg-neutral-800 transition-all">
                <svg width="20" height="20" viewBox="0 0 48 48">
                  <path
                    fill="#FFC107"
                    d="M43.611,20.083H42V20H24v8h11.303c-1.649,4.657-6.08,8-11.303,8c-6.627,0-12-5.373-12-12c0-6.627,5.373-12,12-12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C12.955,4,4,12.955,4,24c0,11.045,8.955,20,20,20c11.045,0,20-8.955,20-20C44,22.659,43.862,21.35,43.611,20.083z"
                  />
                  <path
                    fill="#FF3D00"
                    d="M6.306,14.691l6.571,4.819C14.655,15.108,18.961,12,24,12c3.059,0,5.842,1.154,7.961,3.039l5.657-5.657C34.046,6.053,29.268,4,24,4C16.318,4,9.656,8.337,6.306,14.691z"
                  />
                  <path
                    fill="#4CAF50"
                    d="M24,44c5.166,0,9.86-1.977,13.409-5.192l-6.19-5.238C29.211,35.091,26.715,36,24,36c-5.202,0-9.619-3.317-11.283-7.946l-6.522,5.025C9.505,39.556,16.227,44,24,44z"
                  />
                  <path
                    fill="#1976D2"
                    d="M43.611,20.083H42V20H24v8h11.303c-0.792,2.237-2.231,4.166-4.087,5.571c0.001-0.001,0.002-0.001,0.003-0.002l6.19,5.238C36.971,39.205,44,34,44,24C44,22.659,43.862,21.35,43.611,20.083z"
                  />
                </svg>
                Google
              </button>
              <button className="flex-1 flex items-center justify-center gap-3 font-montserrat font-medium h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 rounded-lg text-sm sm:text-base text-[#333] dark:text-white bg-white dark:bg-[#2a2a2a] cursor-pointer hover:bg-gray-50 dark:hover:bg-neutral-800 transition-all">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="#1877F2">
                  <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                </svg>
                Facebook
              </button>
            </div>

            {/* Register link */}
            <p className="text-center font-montserrat text-sm sm:text-base text-[#666] dark:text-gray-400">
              Don&apos;t have an account?{' '}
              <Link
                href="/register"
                className="font-bold hover:underline"
                style={{ color: '#36D6BA' }}
              >
                Register
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

// Client Component
'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { useRouter } from 'next/navigation';

export default function RegisterPage() {
  const router = useRouter();
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [acceptTerms, setAcceptTerms] = useState(false);

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!firstName.trim()) newErrors.firstName = 'First name is required';
    if (!lastName.trim()) newErrors.lastName = 'Last name is required';
    if (!email.trim()) newErrors.email = 'Email is required';
    else if (!/\S+@\S+\.\S+/.test(email)) newErrors.email = 'Email is invalid';

    if (!password) newErrors.password = 'Password is required';
    else if (password.length < 6) newErrors.password = 'Password must be at least 6 characters';

    if (password && confirmPassword && password !== confirmPassword)
      newErrors.confirmPassword = 'Passwords do not match';

    if (!acceptTerms) newErrors.terms = 'You must accept the terms';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    setIsLoading(true);
    setErrors({});

    try {
      const res = await fetch('/api/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });
      const data = await res.json();

      if (!res.ok) {
        setErrors({ email: data.error || 'Registration failed. User might already exist.' });
      } else {
        router.push('/login');
      }
    } catch (err: any) {
      setErrors({ email: 'An error occurred during registration.' });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="w-full bg-white dark:bg-[#0a0a0a] min-h-[calc(100vh-85px)]">
      <div className="flex flex-col lg:flex-row min-h-[calc(100vh-85px)]">
        {/* Left Side: Illustration */}
        <div className="hidden lg:flex flex-col items-center justify-center relative overflow-hidden lg:w-[40%] xl:w-[45%] bg-[#F0FBF9] dark:bg-[#112220]">
          <div className="w-3/4 max-w-[500px]">
            <Image
              src="/assets/algo_group_119.svg"
              alt="Register illustration"
              width={600}
              height={600}
              className="w-full h-auto opacity-90"
              style={{ width: 'auto', height: 'auto' }}
            />
          </div>
          <div
            className="absolute rounded-full"
            style={{
              right: '5%',
              top: '8%',
              width: '140px',
              height: '140px',
              backgroundColor: '#36D6BA',
              opacity: 0.15,
            }}
          />
          <div
            className="absolute rounded-full"
            style={{
              left: '5%',
              bottom: '8%',
              width: '200px',
              height: '200px',
              backgroundColor: '#269984',
              opacity: 0.1,
            }}
          />
        </div>

        {/* Right Side: Register Form */}
        <div className="flex-1 flex flex-col items-center justify-center px-6 py-12 sm:px-10">
          <div className="w-full max-w-[500px]">
            <h1 className="font-montserrat font-bold text-3xl sm:text-4xl lg:text-5xl text-black dark:text-white mb-3">
              Register
            </h1>
            <p className="font-montserrat text-base sm:text-lg mb-8 text-[#666] dark:text-gray-400">
              Create your account to get started.
            </p>

            <form onSubmit={handleSubmit}>
              {/* Name fields */}
              <div className="flex flex-col sm:flex-row gap-4 mb-5">
                <div className="flex-1">
                  <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm">
                    First name
                  </label>
                  <input
                    type="text"
                    value={firstName}
                    onChange={(e) => setFirstName(e.target.value)}
                    className={`w-full font-montserrat h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.firstName ? 'border-red-500' : ''}`}
                    placeholder="First name"
                  />
                  {errors.firstName && (
                    <p className="text-red-500 text-xs mt-1">{errors.firstName}</p>
                  )}
                </div>
                <div className="flex-1">
                  <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm">
                    Last name
                  </label>
                  <input
                    type="text"
                    value={lastName}
                    onChange={(e) => setLastName(e.target.value)}
                    className={`w-full font-montserrat h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.lastName ? 'border-red-500' : ''}`}
                    placeholder="Last name"
                  />
                  {errors.lastName && (
                    <p className="text-red-500 text-xs mt-1">{errors.lastName}</p>
                  )}
                </div>
              </div>

              {/* Email */}
              <div className="mb-5">
                <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm">
                  Email address
                </label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className={`w-full font-montserrat h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.email ? 'border-red-500' : ''}`}
                  placeholder="Enter your email"
                />
                {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email}</p>}
              </div>

              {/* Password */}
              <div className="mb-5">
                <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm">
                  Password
                </label>
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={`w-full font-montserrat h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.password ? 'border-red-500' : ''}`}
                  placeholder="Create a password"
                />
                {errors.password && <p className="text-red-500 text-xs mt-1">{errors.password}</p>}
              </div>

              {/* Confirm Password */}
              <div className="mb-5">
                <label className="font-montserrat font-bold text-black dark:text-white block mb-2 text-sm">
                  Confirm password
                </label>
                <input
                  type="password"
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className={`w-full font-montserrat h-12 sm:h-13 border-2 border-[#E0E0E0] dark:border-neutral-700 bg-white dark:bg-[#2a2a2a] dark:text-white rounded-lg px-4 text-base outline-none focus:border-[#36D6BA] transition-colors ${errors.confirmPassword ? 'border-red-500' : ''}`}
                  placeholder="Confirm your password"
                />
                {errors.confirmPassword && (
                  <p className="text-red-500 text-xs mt-1">{errors.confirmPassword}</p>
                )}
              </div>

              {/* Terms */}
              <div className="mb-8">
                <label className="flex items-start gap-3 cursor-pointer font-montserrat text-sm">
                  <input
                    type="checkbox"
                    checked={acceptTerms}
                    onChange={(e) => setAcceptTerms(e.target.checked)}
                    className="w-5 h-5 accent-[#36D6BA] mt-0.5"
                  />
                  <span className="text-black dark:text-white">
                    I accept the{' '}
                    <Link href="#" className="font-bold" style={{ color: '#36D6BA' }}>
                      Terms of Service
                    </Link>{' '}
                    and{' '}
                    <Link href="#" className="font-bold" style={{ color: '#36D6BA' }}>
                      Privacy Policy
                    </Link>
                  </span>
                </label>
                {errors.terms && <p className="text-red-500 text-xs mt-1">{errors.terms}</p>}
              </div>

              {/* Register button */}
              <button
                className="w-full font-montserrat font-bold text-white h-12 sm:h-14 rounded-lg text-lg sm:text-xl hover:opacity-90 transition-all cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed"
                style={{ backgroundColor: '#269984', border: 'none' }}
                disabled={isLoading}
              >
                {isLoading ? 'Registering...' : 'Register'}
              </button>
            </form>

            {/* Login link */}
            <p className="text-center font-montserrat mt-6 text-sm sm:text-base text-[#666] dark:text-gray-400">
              Already have an account?{' '}
              <Link
                href="/login"
                className="font-bold hover:underline"
                style={{ color: '#36D6BA' }}
              >
                Login
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import config from '../../payload.config';
import { handleServerFunctions, RootLayout } from '@payloadcms/next/layouts';
import React from 'react';

import { importMap } from './admin/importMap.js';
import '@payloadcms/next/css';

type Args = {
  children: React.ReactNode;
};

const serverFunction = async function (args: any) {
  'use server';
  return handleServerFunctions({
    ...args,
    config,
    importMap,
  });
};

export default function Layout({ children }: Args) {
  return (
    <RootLayout config={config} importMap={importMap} serverFunction={serverFunction}>
      {children}
    </RootLayout>
  );
}

import { getPayload } from 'payload';
import configPromise from '../../../../payload.config';
import { NextResponse } from 'next/server';
import { cookies } from 'next/headers';

export async function POST(req: Request) {
  try {
    const { email, password } = await req.json();
    const payload = await getPayload({ config: configPromise });

    const result = await payload.login({
      collection: 'users',
      data: { email, password },
    });

    if (result.token) {
      const cookieStore = await cookies();
      cookieStore.set('payload-token', result.token, {
        path: '/',
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 60 * 60 * 24 * 7, // 7 days
      });
    }

    return NextResponse.json(result);
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 401 });
  }
}

import { getPayload } from 'payload';
import configPromise from '../../../../payload.config';
import { NextResponse } from 'next/server';

export async function POST(req: Request) {
  try {
    const { email, password, role } = await req.json();
    const payload = await getPayload({ config: configPromise });

    const user = await payload.create({
      collection: 'users',
      data: {
        email,
        password,
        role: role || 'user',
      },
    });

    return NextResponse.json({ message: 'User created successfully', user });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 400 });
  }
}

'use client';

import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import Image from 'next/image';
import { useState, useRef, useEffect } from 'react';
import { useLocale, Locale } from '../i18n/LocaleProvider';
import ThemeToggle from './ThemeToggle';
import { User as UserIcon } from 'lucide-react';

export default function Header({
  isAuthenticated,
  userImage,
}: {
  isAuthenticated?: boolean;
  userImage?: string | null;
}) {
  const router = useRouter();
  const pathname = usePathname();
  const [menuOpen, setMenuOpen] = useState(false);
  const [langDropdownOpen, setLangDropdownOpen] = useState(false);
  const { locale, setLocale, t } = useLocale();
  const dropdownRef = useRef<HTMLDivElement>(null);

  // ... (keep logic same)
  // Close dropdown when clicking outside
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setLangDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const languages: { code: Locale; label: string; flag: string }[] = [
    { code: 'en', label: 'EN', flag: '/flags/gb.png' },
    { code: 'hu', label: 'HU', flag: '/flags/hu.png' },
    { code: 'ro', label: 'RO', flag: '/flags/ro.png' },
  ];

  const currentLang = languages.find((l) => l.code === locale) || languages[0];

  return (
    <header className="fixed top-0 left-0 right-0 z-50 h-[var(--header-height)] bg-[#269984]">
      <div className="max-w-[1400px] mx-auto h-full flex items-center justify-between px-6 lg:px-12">
        {/* Logo */}
        <Link href="/" className="flex-shrink-0">
          <Image
            src="/assets/group_20.svg"
            alt="AlgoRythmics Logo"
            width={294}
            height={57}
            sizes="(max-width: 768px) 150px, 200px"
            className="pointer-events-none select-none"
            style={{
              filter: 'brightness(0) invert(1)',
              height: 'clamp(40px, 4vw, 48px)',
              width: 'auto',
            }}
          />
        </Link>

        {/* Desktop Nav — centre links */}
        <nav className="hidden md:flex items-center gap-5 lg:gap-8">
          <NavLink href="/" label={t('nav.home')} active={pathname === '/'} />
          {isAuthenticated && (
            <>
              <NavLink
                href="/algorithms"
                label={t('nav.algorithms')}
                active={pathname?.startsWith('/algorithms') ?? false}
              />
              <NavLink href="/courses" label={t('nav.courses')} active={pathname === '/courses'} />
            </>
          )}
        </nav>

        {/* Right actions (Desktop) */}
        <div className="hidden md:flex items-center gap-4 lg:gap-6">
          {!isAuthenticated ? (
            <>
              <button
                onClick={() => router.push('/register')}
                className="font-montserrat text-white hover:text-white/80 transition-colors text-sm lg:text-base"
              >
                {t('nav.register')}
              </button>
              <button
                onClick={() => router.push('/login')}
                className="font-montserrat text-white hover:text-white/80 transition-colors text-sm lg:text-base"
              >
                {t('nav.login')}
              </button>
            </>
          ) : (
            <button
              onClick={async () => {
                await fetch('/api/auth/logout', { method: 'POST' });
                router.push('/login');
                router.refresh();
              }}
              className="font-montserrat text-white hover:text-white/80 transition-colors text-sm lg:text-base font-bold"
            >
              Logout
            </button>
          )}

          {isAuthenticated && (
            <Link
              href="/profil"
              className="flex items-center justify-center w-10 h-10 rounded-full border-2 border-white/20 hover:border-white/50 transition-colors overflow-hidden bg-white/10"
            >
              {userImage ? (
                <Image
                  src={userImage}
                  alt="Profile"
                  width={40}
                  height={40}
                  className="w-full h-full object-cover"
                  style={{ width: 'auto', height: 'auto' }}
                />
              ) : (
                <UserIcon className="w-6 h-6 text-white" />
              )}
            </Link>
          )}

          <ThemeToggle />

          {/* Language Dropdown */}
          <div className="relative" ref={dropdownRef}>
            <button
              onClick={() => setLangDropdownOpen(!langDropdownOpen)}
              className="flex items-center gap-2 hover:opacity-80 transition-opacity p-2"
            >
              <img
                src={currentLang.flag}
                alt={currentLang.code}
                width={20}
                height={15}
                className="rounded-sm object-cover"
              />
              <span className="font-montserrat text-white text-sm lg:text-base uppercase">
                {currentLang.code}
              </span>
              <Image
                src="/assets/path_1568.svg"
                alt=""
                width={10}
                height={10}
                style={{
                  width: 'auto',
                  height: 'auto',
                  filter: 'brightness(0) invert(1)',
                  transform: langDropdownOpen ? 'rotate(180deg)' : 'rotate(0deg)',
                  transition: 'transform 0.2s',
                }}
              />
            </button>

            {/* Dropdown Menu */}
            {langDropdownOpen && (
              <div className="absolute top-full right-0 mt-2 w-32 bg-white rounded-lg shadow-xl overflow-hidden py-1 border border-gray-100">
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => {
                      setLocale(lang.code);
                      setLangDropdownOpen(false);
                    }}
                    className={`w-full flex items-center gap-3 px-4 py-2 hover:bg-gray-50 transition-colors ${
                      locale === lang.code
                        ? 'bg-gray-50 font-bold text-[var(--brand-teal)]'
                        : 'text-gray-700'
                    }`}
                  >
                    <img
                      src={lang.flag}
                      alt={lang.code}
                      width={20}
                      height={15}
                      className="rounded-sm object-cover"
                    />
                    <span className="font-montserrat text-sm uppercase">{lang.label}</span>
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Mobile hamburger */}
        <button
          className="md:hidden flex flex-col gap-1.5 p-2"
          onClick={() => setMenuOpen(!menuOpen)}
        >
          <span
            className={`block w-6 h-0.5 bg-white transition-transform ${menuOpen ? 'rotate-45 translate-y-2' : ''}`}
          />
          <span
            className={`block w-6 h-0.5 bg-white transition-opacity ${menuOpen ? 'opacity-0' : ''}`}
          />
          <span
            className={`block w-6 h-0.5 bg-white transition-transform ${menuOpen ? '-rotate-45 -translate-y-2' : ''}`}
          />
        </button>
      </div>

      {/* Mobile menu */}
      {menuOpen && (
        <div className="md:hidden absolute top-[var(--header-height)] left-0 right-0 bg-[#269984] shadow-lg border-t border-white/20">
          <nav className="flex flex-col p-6 gap-4">
            <Link
              href="/"
              className="font-montserrat text-white text-lg"
              onClick={() => setMenuOpen(false)}
            >
              {t('nav.home')}
            </Link>
            {isAuthenticated && (
              <>
                <Link
                  href="/algorithms"
                  className="font-montserrat text-white text-lg"
                  onClick={() => setMenuOpen(false)}
                >
                  {t('nav.algorithms')}
                </Link>
                <Link
                  href="/courses"
                  className="font-montserrat text-white text-lg"
                  onClick={() => setMenuOpen(false)}
                >
                  {t('nav.courses')}
                </Link>
              </>
            )}
            <Link
              href="/contact"
              className="font-montserrat text-white text-lg"
              onClick={() => setMenuOpen(false)}
            >
              {t('nav.contact')}
            </Link>

            <div className="border-t border-white/20 pt-4 mt-2">
              <p className="text-white/60 text-sm font-montserrat mb-2">Language</p>
              <div className="flex gap-4">
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => setLocale(lang.code)}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md border ${
                      locale === lang.code
                        ? 'bg-white text-[#269984] border-white'
                        : 'text-white border-white/30'
                    }`}
                  >
                    <img
                      src={lang.flag}
                      alt={lang.code}
                      width={20}
                      height={15}
                      className="rounded-sm object-cover"
                    />
                    <span className="font-montserrat text-sm uppercase font-bold">{lang.code}</span>
                  </button>
                ))}
              </div>
            </div>

            <hr className="border-white/20" />
            {!isAuthenticated ? (
              <>
                <Link
                  href="/register"
                  className="font-montserrat text-white text-lg"
                  onClick={() => setMenuOpen(false)}
                >
                  {t('nav.register')}
                </Link>
                <Link
                  href="/login"
                  className="font-montserrat text-white text-lg"
                  onClick={() => setMenuOpen(false)}
                >
                  {t('nav.login')}
                </Link>
              </>
            ) : (
              <>
                <Link
                  href="/profil"
                  className="flex items-center gap-3 font-montserrat text-white text-lg"
                  onClick={() => setMenuOpen(false)}
                >
                  <div className="w-8 h-8 rounded-full border border-white/30 overflow-hidden bg-white/10 flex items-center justify-center">
                    {userImage ? (
                      <Image
                        src={userImage}
                        alt="Profile"
                        width={32}
                        height={32}
                        className="w-full h-full object-cover"
                        style={{ width: 'auto', height: 'auto' }}
                      />
                    ) : (
                      <UserIcon className="w-5 h-5 flex-shrink-0" />
                    )}
                  </div>
                  Profile
                </Link>
                <button
                  onClick={async () => {
                    setMenuOpen(false);
                    await fetch('/api/auth/logout', { method: 'POST' });
                    router.push('/login');
                    router.refresh();
                  }}
                  className="font-montserrat text-white text-lg text-left font-bold"
                >
                  Logout
                </button>
              </>
            )}

            <div className="flex items-center gap-2 text-white">
              <ThemeToggle />
              <span className="font-montserrat">Switch Theme</span>
            </div>
          </nav>
        </div>
      )}
    </header>
  );
}

function NavLink({ href, label, active }: { href: string; label: string; active: boolean }) {
  return (
    <Link
      href={href}
      className={`font-montserrat transition-colors text-sm lg:text-[17px] ${
        active ? 'text-white font-bold' : 'text-white/90 hover:text-white'
      }`}
    >
      {label}
    </Link>
  );
}
